import { createMachine, createSlice } from '@zazcart/tools';

// ============================================================================
// TYPES
// ============================================================================

export interface Project {
  id: string;
  path: string;
  name: string;
  harness: {
    progressFile: string;
    featuresFile: string;
  };
}

export interface Feature {
  id: string;
  description: string;
  category: string;
  priority: string;
  status: string;
  passes: boolean;
  steps: string[];
}

export interface Process {
  id: string;
  projectId: string;
  command: string;
  status: 'running' | 'stopped' | 'error';
  pid?: number;
}

export interface LogEntry {
  id: string;
  processId: string;
  timestamp: number;
  content: string;
  level: 'info' | 'warn' | 'error' | 'debug';
}

// State types
interface UIState {
  activeTab: string;
  theme: 'light' | 'dark' | 'system';
  projectOrder: string[];
  sidebarCollapsed: boolean;
  logPanelHeight: number;
}

type ProjectsState = Record<string, Project>;
type ProcessesState = Record<string, Process>;

interface LogsState {
  entries: Record<string, LogEntry[]>;
  autoScroll: boolean;
  filter: string;
}

interface FeaturesState {
  items: Feature[];
  loading: boolean;
  error: string | null;
}

// ============================================================================
// SLICES
// ============================================================================

const uiSlice = createSlice<UIState>({
  id: 'ui',
  cache: { policy: 'session' },
  initial: {
    activeTab: '',
    theme: 'system',
    projectOrder: [],
    sidebarCollapsed: false,
    logPanelHeight: 200,
  },
  reducers: {
    setActiveTab: (state: UIState, tabId: string) => {
      state.activeTab = tabId;
    },
    setTheme: (state: UIState, theme: 'light' | 'dark' | 'system') => {
      state.theme = theme;
    },
    addProject: (state: UIState, projectId: string) => {
      if (!state.projectOrder.includes(projectId)) {
        state.projectOrder.push(projectId);
      }
      state.activeTab = projectId;
    },
    removeProject: (state: UIState, projectId: string) => {
      const idx = state.projectOrder.indexOf(projectId);
      state.projectOrder = state.projectOrder.filter((id) => id !== projectId);
      if (state.activeTab === projectId) {
        state.activeTab = state.projectOrder[Math.max(0, idx - 1)] || '';
      }
    },
    reorderProjects: (state: UIState, order: string[]) => {
      state.projectOrder = order;
    },
    toggleSidebar: (state: UIState) => {
      state.sidebarCollapsed = !state.sidebarCollapsed;
    },
    setLogPanelHeight: (state: UIState, height: number) => {
      state.logPanelHeight = height;
    },
  },
});

const projectsSlice = createSlice<ProjectsState>({
  id: 'projects',
  cache: { policy: 'private' },
  initial: {},
  reducers: {
    set: (state: ProjectsState, project: Project) => {
      state[project.id] = project;
    },
    remove: (state: ProjectsState, projectId: string) => {
      delete state[projectId];
    },
    update: (state: ProjectsState, payload: { id: string; updates: Partial<Project> }) => {
      if (state[payload.id]) {
        Object.assign(state[payload.id], payload.updates);
      }
    },
  },
});

const processesSlice = createSlice<ProcessesState>({
  id: 'processes',
  cache: { policy: 'session' },
  initial: {},
  reducers: {
    spawn: (state: ProcessesState, process: Process) => {
      state[process.id] = process;
    },
    updateStatus: (state: ProcessesState, payload: { id: string; status: Process['status'] }) => {
      if (state[payload.id]) {
        state[payload.id].status = payload.status;
      }
    },
    updatePid: (state: ProcessesState, payload: { id: string; pid: number }) => {
      if (state[payload.id]) {
        state[payload.id].pid = payload.pid;
      }
    },
    kill: (state: ProcessesState, processId: string) => {
      delete state[processId];
    },
  },
});

const MAX_LOGS_PER_PROCESS = 10000;

const logsSlice = createSlice<LogsState>({
  id: 'logs',
  cache: { policy: 'session' },
  initial: {
    entries: {},
    autoScroll: true,
    filter: '',
  },
  reducers: {
    append: (state: LogsState, entry: LogEntry) => {
      if (!state.entries[entry.processId]) {
        state.entries[entry.processId] = [];
      }
      state.entries[entry.processId].push(entry);
      if (state.entries[entry.processId].length > MAX_LOGS_PER_PROCESS) {
        state.entries[entry.processId] = state.entries[entry.processId].slice(-MAX_LOGS_PER_PROCESS);
      }
    },
    clear: (state: LogsState, processId: string) => {
      state.entries[processId] = [];
    },
    clearAll: (state: LogsState) => {
      state.entries = {};
    },
    setAutoScroll: (state: LogsState, autoScroll: boolean) => {
      state.autoScroll = autoScroll;
    },
    setFilter: (state: LogsState, filter: string) => {
      state.filter = filter;
    },
  },
});

const featuresSlice = createSlice<FeaturesState>({
  id: 'features',
  cache: { policy: 'private' },
  initial: {
    items: [],
    loading: false,
    error: null,
  },
  reducers: {
    setFeatures: (state: FeaturesState, features: Feature[]) => {
      state.items = features;
      state.loading = false;
      state.error = null;
    },
    setLoading: (state: FeaturesState, loading: boolean) => {
      state.loading = loading;
    },
    setError: (state: FeaturesState, error: string) => {
      state.error = error;
      state.loading = false;
    },
    updateFeature: (state: FeaturesState, payload: { id: string; updates: Partial<Feature> }) => {
      const idx = state.items.findIndex((f) => f.id === payload.id);
      if (idx !== -1) {
        state.items[idx] = { ...state.items[idx], ...payload.updates };
      }
    },
  },
});

// ============================================================================
// APP MACHINE
// ============================================================================

export const appMachine = createMachine({
  id: 'hq',
  slices: {
    ui: uiSlice,
    projects: projectsSlice,
    processes: processesSlice,
    logs: logsSlice,
    features: featuresSlice,
  },
});

// ============================================================================
// SELECTORS
// ============================================================================

export const selectors = {
  activeProject: (state: AppState) => {
    const activeTab = state.ui.activeTab;
    return activeTab ? state.projects[activeTab] : null;
  },

  projectsArray: (state: AppState) => {
    return state.ui.projectOrder.map((id) => state.projects[id]).filter(Boolean);
  },

  activeProcesses: (state: AppState) => {
    const activeTab = state.ui.activeTab;
    return Object.values(state.processes).filter((p) => p.projectId === activeTab);
  },

  logsForProcess: (state: AppState, processId: string) => {
    const logs = state.logs.entries[processId] || [];
    const filter = state.logs.filter.toLowerCase();
    if (!filter) return logs;
    return logs.filter((log) => log.content.toLowerCase().includes(filter));
  },

  featureStats: (state: AppState) => {
    const features = state.features.items || [];
    const total = features.length;
    const completed = features.filter((f) => f.passes).length;
    return { total, completed, remaining: total - completed };
  },
};

// ============================================================================
// EXPORTS
// ============================================================================

export interface AppState {
  ui: UIState;
  projects: ProjectsState;
  processes: ProcessesState;
  logs: LogsState;
  features: FeaturesState;
}

export type { UIState, ProjectsState, ProcessesState, LogsState, FeaturesState };

